var REPORT_SEASON_GROUP = {"Light Spring": "spring", "True Spring": "spring", "Bright Spring": "spring", "Light Summer": "summer", "True Summer": "summer", "Soft Summer": "summer", "Soft Autumn": "autumn", "True Autumn": "autumn", "Dark Autumn": "autumn", "True Winter": "winter", "Dark Winter": "winter", "Bright Winter": "winter"};
var REPORT_SEASON_DESC = {"Light Spring": {"tone": "Cool & Light", "undertone": "Warm", "contrast": "Low to Medium"}, "True Spring": {"tone": "Warm & Clear", "undertone": "Warm", "contrast": "Medium"}, "Bright Spring": {"tone": "Warm & Bright", "undertone": "Warm", "contrast": "High"}, "Light Summer": {"tone": "Cool & Light", "undertone": "Cool", "contrast": "Low"}, "True Summer": {"tone": "Cool & Muted", "undertone": "Cool", "contrast": "Low to Medium"}, "Soft Summer": {"tone": "Cool & Soft", "undertone": "Cool", "contrast": "Low"}, "Soft Autumn": {"tone": "Warm & Soft", "undertone": "Warm", "contrast": "Low to Medium"}, "True Autumn": {"tone": "Warm & Muted", "undertone": "Warm", "contrast": "Medium"}, "Dark Autumn": {"tone": "Warm & Dark", "undertone": "Warm", "contrast": "High"}, "True Winter": {"tone": "Cool & Clear", "undertone": "Cool", "contrast": "High"}, "Dark Winter": {"tone": "Cool & Dark", "undertone": "Cool", "contrast": "High"}, "Bright Winter": {"tone": "Cool & Bright", "undertone": "Cool", "contrast": "High"}};
var REPORT_SISTERS = {"Light Spring": ["True Spring", "Light Summer"], "True Spring": ["Bright Spring", "Light Spring"], "Bright Spring": ["True Spring", "Bright Winter"], "Light Summer": ["True Summer", "Light Spring"], "True Summer": ["Soft Summer", "Light Summer"], "Soft Summer": ["True Summer", "Soft Autumn"], "Soft Autumn": ["True Autumn", "Soft Summer"], "True Autumn": ["Soft Autumn", "Dark Autumn"], "Dark Autumn": ["True Autumn", "Dark Winter"], "True Winter": ["Bright Winter", "True Summer"], "Dark Winter": ["True Winter", "Dark Autumn"], "Bright Winter": ["True Winter", "Bright Spring"]};

// Tick state: reportTicks[pageKey][itemKey] = true/false
var reportTicks = {};
var reportClientName = '';
var reportSeason = '';

function openReportModal() {
  var best = autoDetectSeason();
  if (best) document.getElementById('report-season-select').value = best;
  var m = document.getElementById('report-modal');
  m.style.display = 'flex';
}
function closeReportModal() {
  document.getElementById('report-modal').style.display = 'none';
}
function closeReportPreview() {
  document.getElementById('report-preview-overlay').style.display = 'none';
}

function autoDetectSeason() {
  var counts = {};
  var groups = Object.keys(OCA_GROUPS);
  var labels = {Summer:['Light','True','Soft'],Winter:['Bright','True','Dark'],Autumn:['Soft','True','Dark'],Spring:['Light','True','Bright']};
  groups.forEach(function(g) {
    var votes = ocaSeasonVotesSub[g] || {};
    var labs = labels[g] || [];
    var seasons = OCA_GROUPS[g];
    labs.forEach(function(label, si) {
      var tally = 0;
      Object.values(votes).forEach(function(v) { if(v===label) tally++; });
      if (tally > 0 && seasons[si]) counts[seasons[si]] = (counts[seasons[si]]||0) + tally;
    });
  });
  var best = null, bestN = 0;
  Object.keys(counts).forEach(function(s) { if(counts[s]>bestN){ bestN=counts[s]; best=s; } });
  return best;
}

function getTick(pageKey, itemKey, defaultVal) {
  if (!reportTicks[pageKey]) reportTicks[pageKey] = {};
  if (reportTicks[pageKey][itemKey] === undefined) reportTicks[pageKey][itemKey] = defaultVal || false;
  return reportTicks[pageKey][itemKey];
}

function toggleReportTick(pageKey, itemKey) {
  getTick(pageKey, itemKey, false);
  reportTicks[pageKey][itemKey] = !reportTicks[pageKey][itemKey];
  var el = document.getElementById('tick-'+pageKey+'-'+itemKey);
  if (el) el.textContent = reportTicks[pageKey][itemKey] ? '★' : '';
}

function previewReport() {
  var name = document.getElementById('report-client-name').value.trim();
  var season = document.getElementById('report-season-select').value;
  if (!name) { alert('Please enter a client name'); return; }
  if (!season) { alert('Please select a season'); return; }
  reportClientName = name;
  reportSeason = season;
  closeReportModal();
  try {
    initReportTicks();
  } catch(e) { alert('initReportTicks error: ' + e.message); return; }
  var container = document.getElementById('report-pages-container');
  try {
    var pages = [
      {n:'Page 1 (Features)',   fn: buildPage1},
      {n:'Page 2 (Skin Tones)', fn: buildPage2},
      {n:'Page 3 (Contrast)',   fn: buildPage3},
      {n:'Page 4 (Cool/Warm)',  fn: buildPage4},
      {n:'Page 5 (Blush)',      fn: buildPage5},
      {n:'Page 6 (Metals)',     fn: buildPage6},
      {n:'Page 7 (Warm/Cool)',  fn: buildPage7},
      {n:'Page 8 (Subseason 1)',fn: function(){ return buildSubseasonPage(0,4,8); }},
      {n:'Page 9 (Subseason 2)',fn: function(){ return buildSubseasonPage(0,4,9); }},
      {n:'Page 10 (Warm Seasons)', fn: function(){
        var s=reportSeason, grp='';
        Object.keys(OCA_GROUPS).forEach(function(g){if(OCA_GROUPS[g].indexOf(s)>=0)grp=g;});
        var isW=((REPORT_SEASON_DESC[s]||{}).undertone||'').indexOf('Warm')>=0;
        var wg=isW?[grp,(grp==='Spring'?'Autumn':'Spring')]:['Spring','Autumn'];
        return buildSeasonCompPage(wg,'Warm Seasons','This page shows a comparison of how you look in all the warm seasons.',10);
      }},
      {n:'Page 11 (Cool Seasons)', fn: function(){
        var s=reportSeason, grp='';
        Object.keys(OCA_GROUPS).forEach(function(g){if(OCA_GROUPS[g].indexOf(s)>=0)grp=g;});
        var isW=((REPORT_SEASON_DESC[s]||{}).undertone||'').indexOf('Warm')>=0;
        var cg=isW?['Summer','Winter']:[grp,(grp==='Summer'?'Winter':'Summer')];
        return buildSeasonCompPage(cg,'Cool Seasons','Lastly, I conducted additional draping to confirm your primary season.',11);
      }},
      {n:'Page 12 (Your Season)',  fn: buildPage12},
      {n:'Page 13 (Stripe)',       fn: buildPage13},
      {n:'Page 14 (Palette 1)',    fn: function(){ return buildPalettePage([0,1,2,3],14); }},
      {n:'Page 15 (Palette 2)',    fn: function(){ return buildPalettePage([4,5],15); }},
      {n:'Page 16 (Out of Season)',fn: buildPage16},
      {n:'Page 17 (Patterns)',     fn: buildPage17},
      {n:'Page 18 (Avoid)',        fn: buildPage18},
      {n:'Page 19 (Lipsticks)',    fn: buildPage19},
      {n:'Page 20 (What Now)',     fn: buildPage20},
    ];
    var html = '';
    for (var i=0; i<pages.length; i++) {
      try {
        html += pages[i].fn();
      } catch(e) {
        html += '<div style="background:red;color:white;padding:20px;margin:10px;font-family:monospace">'
          + '<strong>' + pages[i].n + ' ERROR:</strong><br>' + e.message + '<br>' + (e.stack||'').replace(/\n/g,'<br>') + '</div>';
      }
    }
    container.innerHTML = html;
  } catch(e) {
    container.innerHTML = '<div style="background:red;color:white;padding:20px;font-family:monospace"><strong>REPORT ERROR:</strong><br>' + e.message + '</div>';
  }
  document.getElementById('report-preview-title').textContent = name + ' — ' + season;
  document.getElementById('report-preview-overlay').style.display = 'block';
}

function initReportTicks() {
  var isWarm = ((REPORT_SEASON_DESC[reportSeason]||{}).undertone||'').indexOf('Warm')>=0;
  var isCool = !isWarm;
  getTick('blush','cool', isCool);
  getTick('blush','warm', isWarm);
  var cwVotes = ocaCwVotes[ocaCwMode] || {};
  Object.keys(cwVotes).forEach(function(i) {
    getTick('cw','cool_'+i, cwVotes[i]==='cool');
    getTick('cw','warm_'+i, cwVotes[i]==='warm');
  });
}

// ─── Style helpers ───
function rPage(content) {
  return '<div class="rp-page" style="background:#fff;width:794px;min-height:1050px;border-radius:8px;box-sizing:border-box;font-family:Inter,sans-serif;position:relative;overflow:hidden;padding:32px 40px">'
    + content + '</div>';
}

function rHeader(title) {
  return '<div style="text-align:center;margin-bottom:24px;margin-top:-8px">'
    + '<div style="display:inline-block;background:#2d2d2d;color:#fff;font-family:Cormorant Garamond,serif;font-size:22px;padding:10px 40px;border-radius:40px;font-style:italic;letter-spacing:.5px;border:3px solid #d4b8a0;font-weight:400">'+title+'</div>'
    + '</div>';
}

function rStar(pageKey, itemKey, defaultVal) {
  var active = getTick(pageKey, itemKey, defaultVal);
  var id = 'tick-'+pageKey+'-'+itemKey;
  return '<span id="'+id+'" data-pk="'+pageKey+'" data-ik="'+itemKey+'" class="report-star" style="cursor:pointer;font-size:26px;line-height:1;display:inline-block;user-select:none;color:#FFD700" title="Toggle star">'
    + (active ? '\u2605' : '\u2606') + '</span>';
}

function rFaceImg(w, h, extraStyle) {
  var ws = w ? w+'px' : '100%';
  var hs = h ? h+'px' : '100%';
  if (ocaPhoto) {
    return '<img src="'+ocaPhoto+'" style="width:'+ws+';height:'+hs+';object-fit:cover;object-position:center top;display:block;'+(extraStyle||'')+'">';
  }
  return '<div style="width:'+ws+';height:'+hs+';background:#e8e4e0;display:flex;align-items:center;justify-content:center;font-size:22px;'+(extraStyle||'')+'">&#128247;</div>';
}

function isLightHex(hex) {
  if (!hex || hex[0]!='#') return true;
  var r=parseInt(hex.slice(1,3),16)||0, g=parseInt(hex.slice(3,5),16)||0, b=parseInt(hex.slice(5,7),16)||0;
  return (r*0.299+g*0.587+b*0.114) > 145;
}

function rStripeBar(season, h) {
  var cols = REPORT_STRIPES[season] || [];
  var ht = h || 50;
  return '<div style="display:flex;overflow:hidden;border-radius:4px;height:'+ht+'px">'
    + cols.map(function(c){ return '<div style="flex:1;background:'+c+'"></div>'; }).join('')
    + '</div>';
}

// Colour wheel SVG (oval ring of colour segments)
function rColorWheel(season, size) {
  var sz = size || 180;
  var cols = REPORT_WHEEL_COLS[season] || [];
  if (!cols.length) {
    // fallback: use stripes
    cols = (REPORT_STRIPES[season]||[]).slice(0,16);
  }
  var n = cols.length || 16;
  var cx = sz/2, cy = sz*0.52;
  var rx = sz*0.46, ry = sz*0.5;
  var ir = sz*0.27, iry = sz*0.30;
  var segments = '';
  for (var i=0; i<n; i++) {
    var a1 = (i/n)*2*Math.PI - Math.PI/2;
    var a2 = ((i+1)/n)*2*Math.PI - Math.PI/2;
    var x1o = cx + rx*Math.cos(a1), y1o = cy + ry*Math.sin(a1);
    var x2o = cx + rx*Math.cos(a2), y2o = cy + ry*Math.sin(a2);
    var x1i = cx + ir*Math.cos(a1), y1i = cy + iry*Math.sin(a1);
    var x2i = cx + ir*Math.cos(a2), y2i = cy + iry*Math.sin(a2);
    var la = a2-a1 > Math.PI ? 1 : 0;
    segments += '<path d="M '+x1o+' '+y1o+' A '+rx+' '+ry+' 0 '+la+' 1 '+x2o+' '+y2o
      +' L '+x2i+' '+y2i+' A '+ir+' '+iry+' 0 '+la+' 0 '+x1i+' '+y1i+' Z" fill="'+cols[i]+'"/>';
  }
  var photoHole = '<clipPath id="cp_'+season.replace(/\s/g,'_')+'"><ellipse cx="'+cx+'" cy="'+cy+'" rx="'+(ir-2)+'" ry="'+(iry-2)+'"/></clipPath>'
    + '<image href="'+(ocaPhoto||'')+'" x="'+(cx-ir)+'" y="'+(cy-iry)+'" width="'+(ir*2)+'" height="'+(iry*2)+'" clip-path="url(#cp_'+season.replace(/\s/g,'_')+')" preserveAspectRatio="xMidYMin slice" style="'+(ocaPhoto?'':'display:none')+'"/>';
  return '<svg width="'+sz+'" height="'+sz+'" viewBox="0 0 '+sz+' '+sz+'" style="display:block">'+segments+photoHole+'</svg>';
}

// ─── PAGE 1: Your Personal Features ───
function buildPage1() {
  var slots = OCA_SAMPLE_SLOTS;
  function getSwatch(id) {
    var s = slots.filter(function(x){return x.id===id;})[0];
    return (s && s.colour) ? s.colour : null;
  }
  var swatches = [
    {id:'H1',label:'HAIR'},{id:'E1',label:'EYES'},
    {id:'S1',label:'SKIN 1'},{id:'S2',label:'SKIN 2'},{id:'L1',label:'LIPS'}
  ];
  var swatchHtml = swatches.map(function(s) {
    var col = getSwatch(s.id) || '#e0d8d0';
    var hasc = !!getSwatch(s.id);
    var tc = hasc ? (isLightHex(col)?'#2a2a2a':'#fff') : '#bbb';
    return '<div style="width:190px;height:46px;background:'+col+';border-radius:10px;display:flex;align-items:center;padding:0 16px;margin-bottom:10px;box-shadow:0 1px 4px rgba(0,0,0,0.08)">'
      + '<span style="font-size:13px;font-weight:700;letter-spacing:1.5px;color:'+tc+'">'+s.label+'</span>'
      + '</div>';
  }).join('');

  var introText = '<p style="margin:0 0 10px"><strong>In colour analysis, we consider all your features to create a complete picture.</strong> Each feature is assessed carefully, and through a systematic process, we determine your season.</p>'
    + '<p style="margin:0 0 10px">Over the next few pages, you&#39;ll find a brief overview of how your season was identified, along with the colours that enhance your natural beauty and those that may detract from it.</p>'
    + '<p style="margin:0 0 10px">As you go through these slides, remember that "brighter" isn&#39;t always better. <strong>In colour analysis, the goal is harmony.</strong> We want the colours to complement you, not overpower you! The perfect colours allow you and the shade to shine together, without one dominating the other.</p>'
    + '<p style="margin:0;font-weight:700">Enjoy discovering your best colours!</p>';

  return rPage(
    rHeader('Your Personal Features')
    + '<div style="font-size:13px;line-height:1.9;text-align:center;margin-bottom:28px;color:#222">'+introText+'</div>'
    + '<div style="display:flex;gap:32px;align-items:flex-end;justify-content:center">'
    + '<div style="flex-shrink:0">'+rFaceImg(260, 320, 'border-radius:4px')+'</div>'
    + '<div style="padding-bottom:8px">'+swatchHtml+'</div>'
    + '</div>'
  );
}

// ─── PAGE 2: Skin Tones ───
function buildPage2() {
  var rows = [
    {label:'Cool',    key:'cool'},
    {label:'Neutral', key:'neutral'},
    {label:'Warm',    key:'warm'},
  ];
  var grid = rows.map(function(row) {
    var sw = (OCA_TONE_STRIPS[row.key]||{}).swatches || [];
    // only 3 cols per row (matching screenshot)
    var cols3 = [sw[0]||'#e8c8c0', sw[2]||'#9a5840', sw[4]||'#5a2818'];
    var cells = cols3.map(function(col,ci) {
      var tickKey = row.key+'_'+ci;
      return '<div style="position:relative;width:190px;flex-shrink:0">'
        + '<div style="background:'+col+';border-radius:4px;overflow:hidden;height:210px;position:relative">'
        + rFaceImg(190, 210, 'width:100%;height:210px;object-position:center top')
        + '<div style="position:absolute;top:8px;left:8px;font-size:28px;line-height:1;cursor:pointer;user-select:none" '
        + 'id="tick-skin-'+tickKey+'" data-pk="skin" data-ik="'+tickKey+'" class="report-star" title="Toggle star">'
        + (getTick('skin',tickKey,false)?'\u2605':'')
        + '</div>'
        + '</div>'
        + '</div>';
    }).join('');
    return '<div style="display:flex;align-items:center;gap:8px;margin-bottom:12px">'
      + '<div style="width:40px;flex-shrink:0;font-size:11px;font-weight:700;letter-spacing:1px;writing-mode:vertical-lr;transform:rotate(180deg);text-align:center;color:#333">'+row.label.toUpperCase()+'</div>'
      + '<div style="display:flex;gap:8px">'+cells+'</div>'
      + '</div>';
  }).join('');
  return rPage(
    rHeader('Skin Tones')
    + '<div style="font-size:13px;line-height:1.8;text-align:center;margin-bottom:20px;color:#222">'
    + 'The first step of your colour analysis is to evaluate your skin overtone. I&#39;ve assessed your skin across cool, neutral, and warm tones, ranging from light to dark. A tick has been placed in the frame that best represents your overall skin tone.'
    + '</div>'
    + grid
  );
}

// ─── PAGE 3: Contrast ───
function buildPage3() {
  var skinV = (ocaFundTags&&ocaFundTags.skin) ? ocaFundTags.skin.val : 5;
  var hairV = (ocaFundTags&&ocaFundTags.hair) ? ocaFundTags.hair.val : 8;
  var eyesV = (ocaFundTags&&ocaFundTags.eyes) ? ocaFundTags.eyes.val : 4;
  var vals = [skinV, hairV, eyesV];
  var diff = Math.max.apply(null,vals) - Math.min.apply(null,vals);
  var range = diff<=3 ? 'Low Contrast' : diff<=6 ? 'Medium Contrast' : 'High Contrast';

  function greyHex(v) {
    var g = Math.round(255 - ((v-1)/9)*210); return 'rgb('+g+','+g+','+g+')';
  }
  function tagBar(label, val) {
    var g = greyHex(val);
    var textDark = val > 5;
    // notch shape using two divs
    return '<div style="display:flex;justify-content:center;align-items:center;margin:20px 0">'
      + '<div style="position:relative;width:220px;height:52px">'
      + '<div style="background:'+g+';border-radius:6px;width:100%;height:100%;display:flex;align-items:center;justify-content:center;position:relative;overflow:hidden">'
      + '<div style="position:absolute;right:0;top:0;bottom:0;width:14px;background:white;clip-path:polygon(0 25%,100% 0,100% 100%,0 75%)"></div>'
      + '<span style="font-size:13px;font-weight:700;color:'+(textDark?'#333':'#ddd')+'">'+val+'</span>'
      + '</div>'
      + '</div>'
      + '</div>';
  }

  return rPage(
    rHeader('Contrast')
    + '<div style="font-size:13px;line-height:1.8;text-align:center;margin-bottom:20px;color:#222">'
    + 'The second step of colour analysis is to assess your contrast level. To do this, your image is converted to greyscale (black and white).<br>'
    + 'We then evaluate the shades of your skin, hair, and eyes, measuring the difference between the lightest and darkest tones:'
    + '</div>'
    + '<div style="text-align:center;font-size:14px;line-height:2;color:#222;margin-bottom:24px">'
    + 'Low Contrast: Shade difference of 1-3<br>'
    + 'Medium Contrast: Shade difference of 4-6<br>'
    + 'High Contrast: Shade difference of 7-9'
    + '</div>'
    + tagBar('SKIN', skinV)
    + tagBar('HAIR', hairV)
    + tagBar('EYES', eyesV)
    + '<div style="text-align:center;margin-top:40px;font-size:15px;font-weight:700;color:#222">'+range+'</div>'
  );
}

// ─── PAGE 4: Cool VS Warm ───
