// ─── PAGE 8 & 9: Finding Your Subseason (2 pages) ───
function buildSubseasonPage(rowStart, rowEnd, pageNum) {
  var s = reportSeason;
  var group = '';
  Object.keys(OCA_GROUPS).forEach(function(g) { if(OCA_GROUPS[g].indexOf(s)>=0) group=g; });
  var seasons = OCA_GROUPS[group] || [s];
  var subVotes = ocaSeasonVotesSub[group] || {};
  var rows = (REPORT_SUBSEASON_COLS[group]||{}).rows || [];
  var rowSlice = rows.slice(rowStart, rowEnd);

  var colHeaders = '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:8px">'
    + seasons.map(function(sn){
        return '<div style="text-align:center;font-size:14px;font-weight:700;color:#222;font-family:Cormorant Garamond,serif">'+sn+'</div>';
      }).join('')
    + '</div>';

  var grid = rowSlice.map(function(rowCols, ri) {
    var cells = rowCols.map(function(col, ci) {
      var seasonName = seasons[ci];
      var tickKey = 'sub_'+(rowStart+ri)+'_'+ci;
      // check if this season got votes for this row
      var voted = false;
      Object.keys(subVotes).forEach(function(idx){ if(subVotes[idx]===seasons[ci]) voted=true; });
      return '<div style="position:relative;border-radius:4px;overflow:hidden">'
        + '<div style="background:'+col+';height:170px;position:relative">'
        + rFaceImg(0, 170, 'width:100%;height:170px;object-position:center top')
        + '</div>'
        + '<div style="position:absolute;top:6px;right:6px;font-size:24px;color:#FFD700;text-shadow:0 1px 4px rgba(0,0,0,0.5);cursor:pointer;user-select:none" '
        + 'id="tick-sub'+pageNum+'-'+tickKey+'" data-pk="sub'+(pageNum)+'" data-ik="'+tickKey+'" class="report-star" title="Toggle star">'
        + (getTick('sub'+pageNum,tickKey,false)?'★':'')+'</div>'
        + '</div>';
    }).join('');
    return '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:10px">'+cells+'</div>';
  }).join('');

  var introText = rowStart===0
    ? 'Here, I&#39;m just working out which sub-season you belong to. Now some of these colours will look great but I am looking for the best overall. If I torn you will find I place the tick between two colours.'
    : 'Here, I&#39;m just working out which sub-season you belong to.';

  return rPage(
    rHeader('Finding your subseason')
    + '<div style="font-size:13px;line-height:1.8;text-align:center;margin-bottom:16px;color:#222">'+introText+'</div>'
    + colHeaders + grid
  );
}

